typedef struct _pt {
    float x;
    float y;
    float z;
    float aff;
    /* Stands for affinity */
    int nb_neighbours;
} pt;
typedef struct _pt_diff {
    float aff;
} pt_diff;
typedef struct _connection {
    int idx1;
    int idx2;
    float d;
    struct _connection *next;
} connection;

float norm_pts_nodiff(pt pt1, pt pt2) {
    return (pt1.x-pt2.x)*(pt1.x-pt2.x) + (pt1.y-pt2.y)*(pt1.y-pt2.y) + (pt1.z-
    pt2.z)*(pt1.z-pt2.z);
}

/*
  Differentiation of compute_similarity in reverse (adjoint) mode (with options context):
   gradient     of useful results: d sigma compute_similarity
   with respect to varying inputs: d sigma
*/
void compute_similarity_b(float d, float *db, float sigma, float *sigmab, 
        float compute_similarityb) {
    float val;
    float valb;
    float tempb;
    valb = compute_similarityb;
    tempb = -(exp(-(d/sigma))*valb/sigma);
    *db = *db + tempb;
    *sigmab = *sigmab - d*tempb/sigma;
}

float compute_similarity_nodiff(float d, float sigma) {
    float val;
    val = exp(-d/sigma);
    return val;
}

